# Graduated extraction: promote a single-agent function to a sub-agent node
# Step 1 — inline function in a single agent
def run_pipeline_v1(query: str) -> str:
    from langchain_anthropic import ChatAnthropic
    llm = ChatAnthropic(model="claude-sonnet-5")
    # Retrieval, writing, and review all happen in one chain
    return llm.invoke(
        f"Research and write a report on: {query}. "
        f"Then review it for accuracy."
    ).content

# Step 2 — extract retrieval when context gets too large
def retriever_node(state: dict) -> dict:
    from langchain_anthropic import ChatAnthropic
    from langchain_community.tools import DuckDuckGoSearchRun
    llm = ChatAnthropic(model="claude-haiku-4-5-20251001")
    results = DuckDuckGoSearchRun().run(state["query"])
    summary = llm.invoke(f"Summarise for a writer:\n{results}").content
    return {"search_results": summary}

# Step 3 — the writer now only sees the summary, not raw search results
def writer_node(state: dict) -> dict:
    from langchain_anthropic import ChatAnthropic
    llm = ChatAnthropic(model="claude-sonnet-5")
    draft = llm.invoke(
        f"Write a report on {state['query']} using:\n{state['search_results']}"
    ).content
    return {"draft": draft}

import uuid
import structlog

log = structlog.get_logger()

def traced_node(node_fn):
    """Decorator that attaches a run_id to every log line from this node."""
    def wrapper(state: dict) -> dict:
        run_id = state.get("run_id", str(uuid.uuid4()))
        bound = log.bind(run_id=run_id, node=node_fn.__name__)
        bound.info("node_start", input_keys=list(state.keys()))
        try:
            result = node_fn(state)
            bound.info("node_done", output_keys=list(result.keys()))
            result["run_id"] = run_id  # propagate for downstream nodes
            return result
        except Exception as e:
            bound.error("node_error", error=str(e))
            raise
    return wrapper

@traced_node
def retriever_node(state: dict) -> dict:
    # ... retrieval logic
    return {"search_results": "...", "run_id": state.get("run_id")}

@traced_node
def writer_node(state: dict) -> dict:
    # ... writing logic
    return {"draft": "...", "run_id": state.get("run_id")}
